module up_down_counter (
  input rst_clk,
  input reset,
  input en,
  input dir,
  output reg [3:0] count
);

  always @(posedge rst_clk) begin
    if (reset)
      count <= 4'b0000;
    else if (en) begin
      if (dir)
        count <= count + 1;
      else
        count <= count - 1;
    end
  end

endmodule
